"""Protocol constants for the H3C iNode SSL VPN ("V7") wire protocol.

Every value here was recovered from the unstripped Linux iNode 7.3 client
(``libiNodeSslvpnPt.so`` / ``libvnic.so``) — see ``docs/PROTOCOL.md`` for the
``file.cpp:line`` / ``@0xADDR`` citations.  Nothing here is invented.
"""
from __future__ import annotations

# ---- transport ------------------------------------------------------------
DEFAULT_PORT = 443
HTTP_VERSION = "HTTP/1.1"
UA_V7 = "SSLVPN-Client/7.0"
UA_V3 = "SSLVPN-Client/3.0"
# UA the V3 path spoofs for some requests:
UA_SPOOF = ("Mozilla/4.0 (compatible; MSIE 6.0; Windows NT 5.2; SV1; "
            ".NET CLR 1.1.4322; .NET CLR 2.0.50727)")

# Response header that marks a V7 gateway (else assume V3).
VERSION_SENTINEL = "SSLVPN-Gateway/7.0"

FORM_CONTENT_TYPE = "application/x-www-form-urlencoded"
V7_FORM_KEY = "request="          # POST body is  request=<urlencoded xml>
XML_ROOT = "data"                 # every body/response is <data>...</data>

# ---- cookies --------------------------------------------------------------
SESSION_COOKIE = "svpnginfo"      # server-issued opaque session token
CAPTCHA_COOKIES = ("svpnvldid", "svpnuid", "vldID")
# Cookie sent with the domain-list request:
DOMAIN_COOKIE = "domainId={domain_id}; authId=-1; showOption=1; saveFlag=0; UserName="

# ---- CGI paths (defaults; the real ones are discovered from gatewayinfo) --
PATH_INDEX = "/svpn/index.cgi"
PATH_IMAGE = "/svpn/image.cgi"
PATH_LOGIN_V7 = "/svpn/vpnuser/check.cgi"
PATH_CHALLENGE_V7 = "/svpn/vpnuser/check_return.cgi"
PATH_LOGIN_V3 = "/svpn/vpnuser/login_submit.cgi"
PATH_OLDUSER = "/svpn/olduser_info.cgi?svpnlang=cn"
PATH_KICK = ("/svpn/vpnuser/kickolduser.cgi?OldUserID={old}&NewUserID={new}"
             "&IsKick=1&svpnlang=cn")
PATH_LOGOUT = "/svpn/logout.cgi"

OS_FIELD = "Linux"

# ---- tunnel ---------------------------------------------------------------
TUNNEL_VERB = "NET_EXTEND"        # NET_EXTEND / HTTP/1.1  (custom upgrade verb)
FRAME_HEADER_LEN = 4              # [type u8][subtype u8][len u16 BE]
BIG_BUF_SIZE = 0x14000            # 81920 — client receive buffer
ENTUNNEL_Q_MAX = 255
HEARTBEAT_TICK = 1.0              # heartbeat thread loop tick (usleep 1_000_000)
# The client loop ticks every second but only SENDS a heartbeat every
# KEEPALIVETIME seconds (binary divisor at struct+0x40); use this when the
# gateway does not supply KEEPALIVETIME.
DEFAULT_KEEPALIVE_INTERVAL = 30
HEARTBEAT_FRAME = b"\x02\x01\x00\x00"
DEFAULT_KEEPALIVE_MAX_MISS = 5    # offline after N unanswered heartbeats

# Hard limits to bound memory when talking to a hostile/buggy gateway.
MAX_HEADER_BYTES = 64 * 1024          # response header block cap
MAX_BODY_BYTES = 16 * 1024 * 1024     # Content-Length / total body cap
MAX_CHUNKS = 100_000                  # chunk-count cap for chunked decoding

# Frame types (uint8 ``type`` / ``subtype``)
FRAME_DATA = 1            # sub 0 : raw IP packet payload  -> TUN
FRAME_HEARTBEAT = 2       # sub 1 : keepalive / ack
FRAME_NETCONFIG = 3       # sub 1 empty(err) / sub 2 update / sub 3 DTLS(ignore)
FRAME_LOGOFF = 4          # gateway forced log-off

NETCONFIG_SUB_EMPTY = 1
NETCONFIG_SUB_UPDATE = 2
NETCONFIG_SUB_DTLS = 3

# ---- virtual NIC ----------------------------------------------------------
TUN_DEVICE = "/dev/net/tun"
IFF_TUN = 0x0001
IFF_NO_PI = 0x1000
TUNSETIFF = 0x400454CA
IFNAME_TEMPLATE = "inode%d"
RESOLV_CONF = "/etc/resolv.conf"
RESOLV_MARKER = "#Line Generated by iNode SSL VPN Client"

# ---- network-config param block keys (plaintext KEY:value lines) ----------
NETCFG_KEYS = (
    "IPADDRESS", "SUBNETMASK", "GATEWAY", "PREFIXLENGTH",
    "DNS", "ROUTES", "EXCLUDE ROUTES", "RESTRICT", "KEEPALIVETIME",
    "IPV6ADDRESS", "IPV6GATEWAY", "IPV6DNS", "IPV6ROUTES",
    "EXCLUDE IPV6ROUTES", "IPV6RESTRICT", "PREFIXLENGTH",
)

# ---- Zero-Trust / SPA -----------------------------------------------------
SPA_KNOCK_PORT_GW = 8000          # 0x1f40
SPA_REGISTER_PORT = 19006
SPA_KNOCK_PORT = 59993
SPA_AUTH_PORT = 443
SPA_DECLARED_LEN = 0x0110         # u16be at packet offset 0
SPA_HEADER_LEN = 0x2F             # 47-byte base packet
SPA_AID_LEN = 32
SPA_HOTP_DIGITS = 5               # 5 HOTP digits + 1 Luhn checksum = 6-byte field

# ---- wire enums (DWARF const values) --------------------------------------
# login / challenge result tokens (string compare on <result>)
RESULT_SUCCESS = "Success"
RESULT_CHALLENGE = "Challenge"
RESULT_CHANGEPWD = "CHANGEPWD"
RESULT_PROMPTPWD = "PROMPTPWD"
RESULT_NOT_SUPPORTED = "SSLVPN_NotSupportAuthPkt"

# <type> tokens (challenge kinds)
CHALLENGE_TYPES = ("SMS", "SMS-GW", "SMS-IMC", "PROMPTPWD", "CHANGEPWD")

# ESvpnChallegeResult
CHRESULT_SUCCESS = 0
CHRESULT_NEWCHALLENGE = 1
CHRESULT_FAILED = 2

# EHttpAuthStat / redirect classifier
AUTHSTAT_WAIT_CONN = 0
AUTHSTAT_WAIT_REDIRECT = 1
AUTHSTAT_WAIT_DOMAINLIST = 2

REDIRECT_MIN, REDIRECT_MAX = 300, 307
SUCCESS_STATUS = "200 OK"
